from __future__ import annotations

from dataclasses import dataclass
from typing import Iterable


class CronParseError(ValueError):
    """Raised when a cron expression cannot be parsed."""


@dataclass(frozen=True)
class CronFieldSpec:
    name: str
    min_value: int
    max_value: int


@dataclass(frozen=True)
class CronField:
    spec: CronFieldSpec
    raw: str
    values: tuple[int, ...]

    def is_wildcard(self) -> bool:
        return self.values == tuple(range(self.spec.min_value, self.spec.max_value + 1))

    def is_single(self) -> bool:
        return len(self.values) == 1

    def single_value(self) -> int:
        if not self.is_single():
            raise CronParseError(f"{self.spec.name} is not a single value")
        return self.values[0]

    def is_every_step_from_min(self, step: int) -> bool:
        expected = tuple(range(self.spec.min_value, self.spec.max_value + 1, step))
        return self.values == expected


@dataclass(frozen=True)
class CronSchedule:
    minute: CronField
    hour: CronField
    day_of_month: CronField
    month: CronField
    day_of_week: CronField

    def describe(self) -> str:
        if all(field.is_wildcard() for field in self.fields()):
            return "Every minute"

        if self._is_every_n_minutes():
            step = parse_step(self.minute.raw)
            return f"Every {step} minutes"

        if self._is_every_n_hours_on_the_hour():
            step = parse_step(self.hour.raw)
            return f"Every {step} hours, on the hour"

        parts: list[str] = [self._describe_time()]
        date_description = self._describe_date_constraints()

        if date_description:
            parts.append(date_description)

        return " ".join(parts)

    def fields(self) -> tuple[CronField, CronField, CronField, CronField, CronField]:
        return (
            self.minute,
            self.hour,
            self.day_of_month,
            self.month,
            self.day_of_week,
        )

    def _is_every_n_minutes(self) -> bool:
        return (
            self.minute.raw.startswith("*/")
            and self.hour.is_wildcard()
            and self.day_of_month.is_wildcard()
            and self.month.is_wildcard()
            and self.day_of_week.is_wildcard()
        )

    def _is_every_n_hours_on_the_hour(self) -> bool:
        return (
            self.minute.is_single()
            and self.minute.single_value() == 0
            and self.hour.raw.startswith("*/")
            and self.day_of_month.is_wildcard()
            and self.month.is_wildcard()
            and self.day_of_week.is_wildcard()
        )

    def _describe_time(self) -> str:
        if self.minute.is_single() and self.hour.is_single():
            hour = self.hour.single_value()
            minute = self.minute.single_value()

            if hour == 0 and minute == 0:
                return "At midnight"

            return f"At {hour:02d}:{minute:02d}"

        if self.minute.is_single() and self.hour.is_wildcard():
            return f"At minute {self.minute.single_value()} of every hour"

        return f"At minutes {format_numbers(self.minute.values)} of hours {format_numbers(self.hour.values)}"

    def _describe_date_constraints(self) -> str:
        descriptions: list[str] = []

        if not self.day_of_month.is_wildcard():
            descriptions.append(self._describe_day_of_month())

        if not self.month.is_wildcard():
            descriptions.append(self._describe_month())

        if not self.day_of_week.is_wildcard():
            descriptions.append(self._describe_day_of_week())

        if not descriptions:
            return ""

        return " ".join(descriptions)

    def _describe_day_of_month(self) -> str:
        if self.day_of_month.is_single():
            day = self.day_of_month.single_value()
            if self.month.is_wildcard():
                return f"on the {ordinal(day)} of every month"
            return f"on the {ordinal(day)}"

        return f"on days {format_numbers(self.day_of_month.values)} of the month"

    def _describe_month(self) -> str:
        if self.month.is_single():
            return f"in {MONTH_NAMES[self.month.single_value()]}"

        names = [MONTH_NAMES[value] for value in self.month.values]
        return f"in {format_words(names)}"

    def _describe_day_of_week(self) -> str:
        if is_simple_range(self.day_of_week.raw):
            start, end = parse_range_bounds(self.day_of_week.raw)
            return f"on {DAY_NAMES[start]} through {DAY_NAMES[end]}"

        names = [DAY_NAMES[value] for value in self.day_of_week.values]
        return f"on {format_words(names)}"


FIELD_SPECS = (
    CronFieldSpec("minute", 0, 59),
    CronFieldSpec("hour", 0, 23),
    CronFieldSpec("day_of_month", 1, 31),
    CronFieldSpec("month", 1, 12),
    CronFieldSpec("day_of_week", 0, 6),
)

DAY_NAMES = {
    0: "Sunday",
    1: "Monday",
    2: "Tuesday",
    3: "Wednesday",
    4: "Thursday",
    5: "Friday",
    6: "Saturday",
}

MONTH_NAMES = {
    1: "January",
    2: "February",
    3: "March",
    4: "April",
    5: "May",
    6: "June",
    7: "July",
    8: "August",
    9: "September",
    10: "October",
    11: "November",
    12: "December",
}


def parse_cron(expression: str) -> CronSchedule:
    parts = expression.split()

    if len(parts) != 5:
        raise CronParseError(
            f"Expected 5 cron fields, got {len(parts)}: {expression!r}"
        )

    fields = [
        parse_field(raw_value, spec)
        for raw_value, spec in zip(parts, FIELD_SPECS, strict=True)
    ]

    return CronSchedule(
        minute=fields[0],
        hour=fields[1],
        day_of_month=fields[2],
        month=fields[3],
        day_of_week=fields[4],
    )


def parse_field(raw: str, spec: CronFieldSpec) -> CronField:
    if not raw:
        raise CronParseError(f"{spec.name} field cannot be empty")

    values: set[int] = set()

    for item in raw.split(","):
        if not item:
            raise CronParseError(f"Empty list item in {spec.name}: {raw!r}")

        values.update(parse_field_item(item, spec))

    return CronField(spec=spec, raw=raw, values=tuple(sorted(values)))


def parse_field_item(item: str, spec: CronFieldSpec) -> Iterable[int]:
    base, step = split_step(item, spec)
    start, end = parse_base_range(base, spec)

    if step > end - start + 1:
        raise CronParseError(
            f"Step {step} is larger than range {start}-{end} in {spec.name}: {item!r}"
        )

    return range(start, end + 1, step)


def split_step(item: str, spec: CronFieldSpec) -> tuple[str, int]:
    if "/" not in item:
        return item, 1

    parts = item.split("/")

    if len(parts) != 2 or not parts[0] or not parts[1]:
        raise CronParseError(f"Invalid step syntax in {spec.name}: {item!r}")

    step = parse_int(parts[1], spec.name)

    if step <= 0:
        raise CronParseError(f"Step must be positive in {spec.name}: {item!r}")

    return parts[0], step


def parse_base_range(base: str, spec: CronFieldSpec) -> tuple[int, int]:
    if base == "*":
        return spec.min_value, spec.max_value

    if "-" in base:
        start, end = parse_range_bounds(base)
        validate_value(start, spec)
        validate_value(end, spec)

        if start > end:
            raise CronParseError(
                f"Range start must not exceed end in {spec.name}: {base!r}"
            )

        return start, end

    value = parse_int(base, spec.name)
    validate_value(value, spec)

    return value, value


def parse_range_bounds(text: str) -> tuple[int, int]:
    parts = text.split("-")

    if len(parts) != 2 or not parts[0] or not parts[1]:
        raise CronParseError(f"Invalid range syntax: {text!r}")

    return int(parts[0]), int(parts[1])


def parse_int(text: str, field_name: str) -> int:
    if not text.isdigit():
        raise CronParseError(f"Expected an integer in {field_name}: {text!r}")

    return int(text)


def validate_value(value: int, spec: CronFieldSpec) -> None:
    if value < spec.min_value or value > spec.max_value:
        raise CronParseError(
            f"{spec.name} value {value} is outside allowed range "
            f"{spec.min_value}-{spec.max_value}"
        )


def parse_step(raw: str) -> int:
    if "/" not in raw:
        raise CronParseError(f"No step found in field: {raw!r}")

    return int(raw.split("/", 1)[1])


def is_simple_range(raw: str) -> bool:
    return "," not in raw and "/" not in raw and "-" in raw


def format_numbers(values: tuple[int, ...]) -> str:
    return format_words([str(value) for value in values])


def format_words(words: list[str]) -> str:
    if not words:
        return ""

    if len(words) == 1:
        return words[0]

    if len(words) == 2:
        return f"{words[0]} and {words[1]}"

    return f"{', '.join(words[:-1])}, and {words[-1]}"


def ordinal(value: int) -> str:
    if 10 <= value % 100 <= 20:
        suffix = "th"
    else:
        suffix = {1: "st", 2: "nd", 3: "rd"}.get(value % 10, "th")

    return f"{value}{suffix}"


